section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-monitoring.json",
  "title": "API Monitoring",
  "type": "object",
  "required": [
    "artefact_id",
    "api_id",
    "metrics_backend",
    "red_metrics",
    "structured_log_fields",
    "liveness_probe",
    "readiness_probe",
    "slos",
    "alert_rules",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "api_id": {
      "type": "string",
      "description": "service id or repo slug",
      "minLength": 1
    },
    "metrics_backend": {
      "type": "string",
      "description": "prometheus|datadog|grafana-cloud|cloud-native",
      "minLength": 1
    },
    "red_metrics": {
      "type": "object",
      "description": "{rate_metric, errors_metric, duration_metric} naming conventions"
    },
    "structured_log_fields": {
      "type": "array",
      "description": "minimum required fields [ts, level, request_id, route, status, latency_ms]",
      "minItems": 1
    },
    "liveness_probe": {
      "type": "string",
      "description": "path responding 200 only when the process is alive",
      "minLength": 1
    },
    "readiness_probe": {
      "type": "string",
      "description": "path responding 200 only when ready to serve traffic",
      "minLength": 1
    },
    "slos": {
      "type": "array",
      "description": "list of {journey, sli_definition, target, window, error_budget}",
      "minItems": 1
    },
    "alert_rules": {
      "type": "array",
      "description": "list of {name, expr, for_minutes, severity, runbook_url}",
      "minItems": 1
    }
  },
  "additionalProperties": false
}
